func TestGenerateMainPrintsIntegerExpression(t *testing.T) {
	file := parseOK(t, `fn main() {
    println(40 + 2 * 3)
}
`)
	ir, err := Generate(file, Options{
		SourcePath: "/tmp/main.osty",
		Target:     "x86_64-unknown-linux-gnu",
	})
	if err != nil {
		t.Fatalf("Generate: %v", err)
	}
	text := string(ir)
	for _, want := range []string{
		"; Code generated by osty LLVM backend. DO NOT EDIT.",
		`; Osty: /tmp/main.osty`,
		`source_filename = "/tmp/main.osty"`,
		`target triple = "x86_64-unknown-linux-gnu"`,
		`@.fmt_i64 = private unnamed_addr constant [5 x i8] c"%ld\0A\00"`,
		`declare i32 @printf(ptr, ...)`,
		`define i32 @main() {`,
		`%t0 = mul i64 2, 3`,
		`%t1 = add i64 40, %t0`,
		`call i32 (ptr, ...) @printf(ptr @.fmt_i64, i64 %t1)`,
		`ret i32 0`,
	} {
		if !strings.Contains(text, want) {
			t.Fatalf("IR missing %q:\n%s", want, text)
		}
	}
}

